## Deobfuscated Code

```javascript
// Constants
var TAU = 6.283;          // 2π (full circle in radians)
var PHI = 1.618;          // Golden ratio
var SQRT_HALF = 0.707;    // √(1/2)

// Simulation parameters
var config = {
    repulsion: 4000,           // Repulsive force strength between nodes
    springForce: 0.004,        // Default spring stiffness
    resistance: 0.92,          // Velocity damping factor (friction)
    centerAttractance: 0.0003, // Force pulling nodes toward center
    maxParticles: 40,          // Max number of ambient particles
    attenuation: 0.04,         // Particle velocity decay
    phase: 0.06                // Camera/view smoothing factor
};

// Define 6 nodes in a graph
var nodes = [
    { id: "hub",     label: "Nexus",   r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Define 8 spring connections (edges) between nodes
var edges = [
    { a: "hub",   b: "alpha",   rest: 160, k: 0.006 },
    { a: "hub",   b: "beta",    rest: 160, k: 0.005 },
    { a: "hub",   b: "gamma",   rest: 170, k: 0.004 },
    { a: "hub",   b: "delta",   rest: 170, k: 0.004 },
    { a: "hub",   b: "epsilon", rest: 180, k: 0.003 },
    { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
    { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
    { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// Camera state (smooth follow)
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Ambient particles
var particles = [];
var frameCount = 0;

// Find a node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Physics simulation step
function simulate() {
    // 1. Repulsive forces between ALL node pairs (like Coulomb's law)
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = config.repulsion / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2. Spring forces along edges (Hooke's law)
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNode(edges[e].a);
        var nodeB = findNode(edges[e].b);
        if (!nodeA || !nodeB) continue;
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || config.springForce) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // 3. Apply centering force, damping, and update positions
    for (var n = 0; n < nodes.length; n++) {
        nodes[n].vx += (400 - nodes[n].x) * config.centerAttractance;
        nodes[n].vy += (300 - nodes[n].y) * config.centerAttractance;
        nodes[n].vx *= config.resistance;
        nodes[n].vy *= config.resistance;
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

// Spawn a decorative particle from a random node
function spawnParticle() {
    if (particles.length >= config.maxParticles) return;
    var node = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;
    particles.push({
        x: node.x,
        y: node.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * SQRT_HALF
    });
}

// Update all particles (move, age, remove dead ones)
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        p.vx *= (1 - config.attenuation * 0.125);
        p.vy *= (1 - config.attenuation * 0.125);
        p.x += p.vx;
        p.y += p.vy;
        p.age++;
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}

// Smooth camera interpolation
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * config.phase;
    camera.y += (cameraTarget.y - camera.y) * config.phase;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * config.phase;
}

// Main loop
function tick() {
    simulate();
    updateParticles();
    updateCamera();
    if (frameCount % 3 === 0) spawnParticle();
    frameCount++;
}

setInterval(tick, 16); // ~60 FPS
```

## What It Does

This is a **force-directed graph layout simulation** — the physics engine behind an interactive node-and-edge visualization. Specifically:

1. **6 named nodes** ("Nexus" as a hub, plus Alpha, Beta, Gamma, Delta, Epsilon) are connected by **8 spring edges** in a hub-and-spoke topology
2. **Three forces** act on every node each frame:
   - **Repulsion** — all nodes push each other apart (inverse-square law, like charged particles)
   - **Spring attraction** — connected nodes are pulled toward their resting distances (Hooke's law)
   - **Centering gravity** — a gentle pull toward the center point (400, 300) to prevent drift
3. **Velocity damping** (0.92×) simulates friction so the system settles into equilibrium
4. **Decorative particles** spawn from random nodes every 3 frames, drift outward, slow down, and die after 800–2000 frames — creating a visual "aura" effect
5. A **smooth camera** lerps toward a target position at 6% per frame

This is **purely the simulation/physics layer** — there's no rendering code here. It would typically be paired with a Canvas or SVG renderer that draws the nodes, edges, and particles each frame. The result would be an animated, organic-looking network graph that gently bounces into a stable layout.
